1	// --- Rates, fees, and thresholds ---
2	const PROCESSING_FEE = 5;
3	const FIRST_INSURANCE_RATE = 0.1;
4	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
5	const LOYALTY_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const CURSE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const BLOCK_SIZE = 3;
11	const BLOCK_BASE_PREMIUM = 60;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
15	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
16	
17	// --- Item catalog ---
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const INSURANCE_VALUE: Record<string, number> = {
28	  sword: 1000,
29	  amulet: 600,
30	  staff: 800,
31	  potion: 400,
32	  rune: 250,
33	  moonstone: 250,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	// --- Domain types ---
39	type Customer = { yearsWithMHPCO: number };
40	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
41	type QuoteStep = { op: "quote"; items: Item[] };
42	type Damage = { itemType: string; amount: number };
43	type Incident = { cause: string; damages: Damage[] };
44	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
45	type Step = QuoteStep | ClaimStep;
46	type Input = { customer: Customer; steps: Step[] };
47	type QuoteResult = { premium: number };
48	type ClaimResult = { payout: number; remainingCap: number };
49	type StepResult = QuoteResult | ClaimResult;
50	
51	const countBy = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> => {
52	  const counts = new Map<string, number>();
53	  for (const item of items) {
54	    const key = keyOf(item);
55	    counts.set(key, (counts.get(key) ?? 0) + 1);
56	  }
57	  return counts;
58	};
59	
60	const countByType = (items: Item[]): Map<string, number> =>
61	  countBy(items, (item) => item.type);
62	
63	const basePremiumForType = (type: string, count: number): number => {
64	  const unit = BASE_PREMIUM[type];
65	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
66	    return BLOCK_BASE_PREMIUM;
67	  }
68	  return unit * count;
69	};
70	
71	const basePremium = (items: Item[]): number =>
72	  Array.from(countByType(items)).reduce(
73	    (total, [type, count]) => total + basePremiumForType(type, count),
74	    0,
75	  );
76	
77	// MHPCO always rounds premiums in its own favor (up).
78	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
79	
80	const isCursed = (item: Item): boolean => item.cursed === true;
81	const isHighlyEnchanted = (item: Item): boolean =>
82	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
83	
84	const itemSurcharge = (item: Item): number => {
85	  const unit = BASE_PREMIUM[item.type];
86	  const curseSurcharge = isCursed(item) ? unit * CURSE_RATE : 0;
87	  const enchantmentSurcharge = isHighlyEnchanted(item)
88	    ? unit * HIGH_ENCHANTMENT_RATE
89	    : 0;
90	  return curseSurcharge + enchantmentSurcharge;
91	};
92	
93	const sumItemSurcharges = (items: Item[]): number =>
94	  items.reduce((total, item) => total + itemSurcharge(item), 0);
95	
96	const isLoyalCustomer = (customer: Customer): boolean =>
97	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
98	
99	const loyaltyDiscount = (base: number, customer: Customer): number =>
100	  isLoyalCustomer(customer) ? base * LOYALTY_RATE : 0;
101	
102	const firstInsuranceSurcharge = (base: number): number =>
103	  base * FIRST_INSURANCE_RATE;
104	
105	const followUpDiscount = (base: number, stepIndex: number): number =>
106	  stepIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
107	
108	const quotePremium = (
109	  { items }: QuoteStep,
110	  customer: Customer,
111	  stepIndex: number,
112	): QuoteResult => {
113	  const base = basePremium(items);
114	  const premium =
115	    base +
116	    sumItemSurcharges(items) +
117	    firstInsuranceSurcharge(base) -
118	    loyaltyDiscount(base, customer) -
119	    followUpDiscount(base, stepIndex) +
120	    PROCESSING_FEE;
121	  return { premium: roundUpInMHPCOFavor(premium) };
122	};
123	
124	const insuranceSum = (items: Item[]): number =>
125	  items.reduce((total, item) => total + INSURANCE_VALUE[item.type], 0);
126	
127	const policyCap = (items: Item[]): number =>
128	  CAP_MULTIPLIER * insuranceSum(items);
129	
130	const triggersHighEnchantmentClause = (item: Item): boolean =>
131	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
132	
133	const reimbursableAmount = (item: Item, amount: number): number =>
134	  triggersHighEnchantmentClause(item)
135	    ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
136	    : amount;
137	
138	const damagePayout = (damage: Damage, items: Item[]): number => {
139	  const item = items.find((i) => i.type === damage.itemType)!;
140	  return Math.max(reimbursableAmount(item, damage.amount) - DEDUCTIBLE, 0);
141	};
142	
143	const totalPayout = (damages: Damage[], items: Item[]): number =>
144	  damages.reduce((total, damage) => total + damagePayout(damage, items), 0);
145	
146	const remainingCapFor = (
147	  policy: number,
148	  items: Item[],
149	  remainingCaps: Map<number, number>,
150	): number => remainingCaps.get(policy) ?? policyCap(items);
151	
152	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
153	  const itemCounts = countByType(items);
154	  const damageCounts = countBy(damages, (d) => d.itemType);
155	  for (const [type, damageCount] of damageCounts) {
156	    const policyCount = itemCounts.get(type) ?? 0;
157	    if (damageCount > policyCount) {
158	      throw new Error(
159	        `Claim references ${damageCount} damages of type "${type}" but policy covers only ${policyCount}`,
160	      );
161	    }
162	  }
163	};
164	
165	const processClaim = (
166	  step: ClaimStep,
167	  steps: Step[],
168	  remainingCaps: Map<number, number>,
169	): ClaimResult => {
170	  const { items } = steps[step.policy] as QuoteStep;
171	  validateDamageCounts(step.incident.damages, items);
172	  const desired = totalPayout(step.incident.damages, items);
173	  const available = remainingCapFor(step.policy, items, remainingCaps);
174	  const payout = Math.floor(Math.min(desired, available));
175	  const remainingCap = available - payout;
176	  remainingCaps.set(step.policy, remainingCap);
177	  return { payout, remainingCap };
178	};
179	
180	const processStep = (
181	  step: Step,
182	  index: number,
183	  steps: Step[],
184	  customer: Customer,
185	  remainingCaps: Map<number, number>,
186	): StepResult =>
187	  step.op === "quote"
188	    ? quotePremium(step, customer, index)
189	    : processClaim(step, steps, remainingCaps);
190	
191	export const run = (input: Input): { results: StepResult[] } => {
192	  const remainingCaps = new Map<number, number>();
193	  return {
194	    results: input.steps.map((step, index) =>
195	      processStep(step, index, input.steps, input.customer, remainingCaps),
196	    ),
197	  };
198	};
